//  ShoppingApp
//
//  修复建议：添加空值检查以防止 EXC_BAD_ACCESS 崩溃
//

#import "CartViewController.h"

@interface CartViewController ()
@property (weak, nonatomic) IBOutlet UITableView *cartTableView;
@property (weak, nonatomic) IBOutlet UILabel *totalPriceLabel;
@property (weak, nonatomic) IBOutlet UIButton *checkoutButton;
@property (strong, nonatomic) NSMutableArray *cartData;
@end

@implementation CartViewController

#pragma mark - 修复后的 viewWillAppear 方法

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];

    // 🔧 修复1: 检查关键UI组件是否正确连接
    if (![self validateUIComponents]) {
        NSLog(@"❌ CartViewController: UI组件验证失败");
        [self handleUIComponentError];
        return;
    }

    // 🔧 修复2: 确保数据源已初始化
    if (![self validateDataSources]) {
        NSLog(@"❌ CartViewController: 数据源验证失败");
        [self initializeDefaultData];
    }

    // 🔧 修复3: 安全执行原有逻辑
    [self refreshCartDisplay];
    [self updateTotalPrice];

    NSLog(@"✅ CartViewController: viewWillAppear 执行成功");
}

#pragma mark - 验证方法

- (BOOL)validateUIComponents {
    // 检查所有关键的IBOutlet连接
    NSArray *requiredComponents = @[
        @{@"component": self.cartTableView, @"name": @"cartTableView"},
        @{@"component": self.totalPriceLabel, @"name": @"totalPriceLabel"},
        @{@"component": self.checkoutButton, @"name": @"checkoutButton"}
    ];

    for (NSDictionary *componentInfo in requiredComponents) {
        if (!componentInfo[@"component"]) {
            NSLog(@"❌ 缺失组件: %@", componentInfo[@"name"]);

            // 上报错误到分析平台
            [self reportError:@"missing_ui_component"
                     userInfo:@{@"missing_component": componentInfo[@"name"]}];

            return NO;
        }
    }

    return YES;
}

- (BOOL)validateDataSources {
    // 检查数据源完整性
    if (!self.cartData) {
        NSLog(@"❌ cartData 为空");
        return NO;
    }

    return YES;
}

#pragma mark - 错误处理

- (void)handleUIComponentError {
    // 尝试重新初始化UI组件
    [self setupUIComponents];

    // 如果仍然失败，显示错误状态
    if (![self validateUIComponents]) {
        [self showErrorState:@"界面组件加载失败，请重启应用"];
    }
}

- (void)setupUIComponents {
    // 尝试从代码重新创建缺失的UI组件
    if (!self.cartTableView && self.view) {
        // 如果tableView缺失，创建一个临时的
        UITableView *tableView = [[UITableView alloc] initWithFrame:self.view.bounds];
        tableView.delegate = self;
        tableView.dataSource = self;
        [self.view addSubview:tableView];
        self.cartTableView = tableView;

        NSLog(@"🔧 临时创建了 cartTableView");
    }
}

- (void)initializeDefaultData {
    if (!self.cartData) {
        self.cartData = [[NSMutableArray alloc] init];
        NSLog(@"🔧 初始化了空的购物车数据");
    }
}

- (void)showErrorState:(NSString *)errorMessage {
    UIAlertController *alert = [UIAlertController
        alertControllerWithTitle:@"购物车暂时无法使用"
        message:errorMessage
        preferredStyle:UIAlertControllerStyleAlert];

    UIAlertAction *okAction = [UIAlertAction
        actionWithTitle:@"知道了"
        style:UIAlertActionStyleDefault
        handler:^(UIAlertAction * _Nonnull action) {
            // 返回上一页面
            [self.navigationController popViewControllerAnimated:YES];
        }];

    [alert addAction:okAction];
    [self presentViewController:alert animated:YES completion:nil];
}

#pragma mark - 安全的UI更新方法

- (void)refreshCartDisplay {
    // 安全的tableView刷新
    if (self.cartTableView) {
        dispatch_async(dispatch_get_main_queue(), ^{
            @try {
                [self.cartTableView reloadData];
            } @catch (NSException *exception) {
                NSLog(@"❌ tableView reload 异常: %@", exception.reason);
                [self reportError:@"tableview_reload_exception"
                         userInfo:@{@"exception": exception.reason ?: @"unknown"}];
            }
        });
    }
}

- (void)updateTotalPrice {
    if (!self.totalPriceLabel || !self.cartData) {
        return;
    }

    @try {
        CGFloat total = [self calculateTotalPrice];
        NSString *totalText = [NSString stringWithFormat:@"总计: ¥%.2f", total];

        dispatch_async(dispatch_get_main_queue(), ^{
            self.totalPriceLabel.text = totalText;
        });
    } @catch (NSException *exception) {
        NSLog(@"❌ 计算总价异常: %@", exception.reason);

        // 设置默认文本
        dispatch_async(dispatch_get_main_queue(), ^{
            self.totalPriceLabel.text = @"总计: ¥0.00";
        });
    }
}

- (CGFloat)calculateTotalPrice {
    CGFloat total = 0.0f;

    for (NSDictionary *item in self.cartData) {
        if ([item isKindOfClass:[NSDictionary class]]) {
            NSNumber *price = item[@"price"];
            NSNumber *quantity = item[@"quantity"];

            if (price && quantity) {
                total += [price floatValue] * [quantity integerValue];
            }
        }
    }

    return total;
}

#pragma mark - 错误上报

- (void)reportError:(NSString *)errorType userInfo:(NSDictionary *)userInfo {
    // 这里集成你们的错误上报SDK
    // 例如：Firebase Crashlytics, Bugly等

    NSLog(@"🔍 错误上报: %@ - %@", errorType, userInfo);

    // 示例代码：
    /*
    [[CrashlyticsService shared] recordError:errorType
                                    userInfo:userInfo
                                  controller:NSStringFromClass([self class])];
    */
}

@end
